import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { FileText, Book, Scale, Calculator, Menu, X, Sun, Moon, Home } from 'lucide-react';

const Layout = ({ children, darkMode, toggleDarkMode }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);
  const location = useLocation();

  const navigation = [
    { name: 'Home', href: '/', icon: Home },
    { name: 'Pleadings', href: '/pleadings', icon: FileText },
    { name: 'Motions', href: '/motions', icon: Scale, 
      submenu: [
        { name: 'Motion for name correction', href: '/motions/name-correction' },
        { name: 'Motion 1', href: '/motions/motion-1' },
        { name: 'Motion 2', href: '/motions/motion-2' },
      ]
    },
    { name: 'Declaration', href: '/declaration', icon: Calculator },
  ];

  const isCurrentPath = (path) => {
    return location.pathname === path;
  };

  const Sidebar = ({ mobile = false }) => (
    <div className={`${mobile ? 'block' : 'hidden'} lg:block h-full`}>
      <div className="flex h-full min-h-0 flex-col">
        <div className="flex h-14 items-center border-b border-gray-700 px-4">
          <Link to="/" className="flex items-center gap-2">
            <span className="text-lg font-semibold text-gray-200">Wiki Paralegal</span>
          </Link>
          <button
            onClick={toggleDarkMode}
            className="ml-auto lg:hidden p-2 text-gray-400 hover:text-gray-200"
          >
            {darkMode ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
          </button>
        </div>
        <nav className="flex-1 space-y-1 px-2 py-4">
          {navigation.map((item) => (
            <div key={item.name}>
              <Link
                to={item.href}
                className={`${
                  isCurrentPath(item.href)
                    ? 'bg-gray-800 text-white'
                    : 'text-gray-400 hover:bg-gray-800 hover:text-white'
                } group flex items-center rounded-md px-2 py-2 text-sm font-medium`}
              >
                <item.icon className="mr-3 h-5 w-5 flex-shrink-0" />
                {item.name}
              </Link>
              {item.submenu && (
                <div className="ml-8 mt-1 space-y-1">
                  {item.submenu.map((subItem) => (
                    <Link
                      key={subItem.name}
                      to={subItem.href}
                      className={`${
                        isCurrentPath(subItem.href)
                          ? 'bg-gray-800 text-white'
                          : 'text-gray-400 hover:bg-gray-800 hover:text-white'
                      } group flex items-center rounded-md px-2 py-1.5 text-sm`}
                    >
                      {subItem.name}
                    </Link>
                  ))}
                </div>
              )}
            </div>
          ))}
        </nav>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-gray-900">
      {/* Sidebar for desktop */}
      <div className="hidden lg:fixed lg:inset-y-0 lg:flex lg:w-64 lg:flex-col bg-gray-900 border-r border-gray-700">
        <Sidebar />
      </div>

      {/* Mobile menu button */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-40 flex h-14 items-center border-b border-gray-700 bg-gray-900 px-4">
        <button
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          className="text-gray-400 hover:text-gray-200"
        >
          <Menu className="h-6 w-6" />
        </button>
        <span className="ml-4 text-lg font-semibold text-gray-200">Wiki Paralegal</span>
        <button
          onClick={toggleDarkMode}
          className="ml-auto p-2 text-gray-400 hover:text-gray-200"
        >
          {darkMode ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
        </button>
      </div>

      {/* Mobile menu */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 z-50 lg:hidden">
          <div className="fixed inset-0 bg-gray-900/80" onClick={() => setIsMobileMenuOpen(false)} />
          <div className="fixed inset-y-0 left-0 w-64 bg-gray-900 border-r border-gray-700">
            <div className="flex h-14 items-center justify-between border-b border-gray-700 px-4">
              <span className="text-lg font-semibold text-gray-200">Wiki Paralegal</span>
              <button
                onClick={() => setIsMobileMenuOpen(false)}
                className="text-gray-400 hover:text-gray-200"
              >
                <X className="h-6 w-6" />
              </button>
            </div>
            <Sidebar mobile />
          </div>
        </div>
      )}

      {/* Main content */}
      <div className="flex-1 lg:pl-64">
        <main className="py-14 px-4 sm:px-6 lg:px-8">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;
